//   wRow: tileK
//   mulVec: tileK
//   yTile: tileM
//   bTile: tileM
//   tmpTile: tileM
// Total ~ (3*tileK + 3*tileM) * 4 bytes
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;  // per-core conservative
static constexpr uint32_t ALIGN_ELEMS_M = 64;            // prefer multiples of 64 for burst
static constexpr uint32_t ALIGN_ELEMS_K = 64;

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    GemmLogSumExpLeakyReluLeakyReluGeluGeluCustomTilingData tiling;

    const auto *x_shape = context->GetInputShape(0);
    const auto *w_shape = context->GetInputShape(1);
    const auto *b_shape = context->GetInputShape(2);

    // Shapes:
    // x: [N, K]
    // w: [M, K]
    // b: [M]
    const uint32_t n = static_cast<uint32_t>(x_shape->GetOriginShape().GetStorageShape()[0]);
    const uint32_t k = static_cast<uint32_t>(x_shape->GetOriginShape().GetStorageShape()[1]);
    const uint32_t m = static_cast<uint32_t>(w_shape->GetOriginShape().GetStorageShape()[0]);

    // Compute tiles from UB budget: bytes >= 4*(3*tileK + 3*tileM)
    // Let tileK target 128, tileM 256, adjust by bounds and budget.
    uint32_t tileK = 128;
    uint32_t tileM = 256;

    // Adjust by limits
    if (tileK > k) tileK = AlignDown(k, ALIGN_ELEMS_K);
    if (tileK == 0) tileK = k;
    if (tileM > m) tileM = AlignDown(m, ALIGN_ELEMS_M);
    if (tileM == 0) tileM = m;

    // Check budget and shrink if needed
    auto bytes_need = 4u * (3u * tileK + 3u * tileM);
    while (bytes_need > UB_BUDGET_BYTES && (tileM >= ALIGN_ELEMS_M || tileK >= ALIGN_ELEMS_K)) {
