        if (tileK >= ALIGN_ELEMS_K && bytes_need > UB_BUDGET_BYTES) {
            tileK = AlignDown(tileK / 2u, ALIGN_ELEMS_K);
            if (tileK == 0) tileK = ALIGN_ELEMS_K;
        }
        bytes_need = 4u * (3u * tileK + 3u * tileM);
    }

    // BlockDim: parallel over N rows
    uint32_t blockDim = n;
    if (blockDim < 4u) blockDim = 4u;
    if (blockDim > 24u) blockDim = 24u;
    context->SetBlockDim(blockDim);

    tiling.set_n(n);
    tiling.set_m(m);
    tiling.set_k(k);
    tiling.set_tileM(tileM);
    tiling.set_tileK(tileK);
    tiling.set_blockDim(blockDim);
